function fixPipeline(input) {
  var output = [];
  for (var i = 0; i < input.length; i++) {
    var obj = input[i];
    if ('b' in obj) {
      var nestedArray = obj['b'];
      for (var j = 0; j < nestedArray.length; j++) {
        var nestedObj = nestedArray[j];
        output.push({ a: obj.a, c: nestedObj.c });
      }
    } else {
      output.push({ a: obj.a });
    }
  }
  return output;
}

