class Solution:
  def fix_pipeline(self, input):
    output = []
    for obj in input:
      if 'b' in obj:
        nested_array = obj['b']
        for nested_obj in nested_array:
          output.append({ 'a': obj['a'], 'c': nested_obj['c'] })
      else:
        output.append({ 'a': obj['a'] })
    return output;
